"use client";

import { createContext, useContext } from "react";
import type { StoreAdapter } from "./adapter/types";
import type { SchemaDefinition } from "./schema/types";

/**
 * Context value for the store provider
 */
export interface StoreContextValue<T extends Record<string, unknown>> {
  adapter: StoreAdapter<T>;
  schema: SchemaDefinition;
  tableId: string;
}

/**
 * React context for the store adapter
 * @internal
 */
export const StoreContext = createContext<StoreContextValue<
  Record<string, unknown>
> | null>(null);

/**
 * Hook to access the store context
 * Returns null if used outside of DataTableStoreProvider
 */
export function useStoreContext<
  T extends Record<string, unknown> = Record<string, unknown>,
>(): StoreContextValue<T> {
  const context = useContext(StoreContext) as StoreContextValue<T> | null;
  if (!context) {
    throw new Error(
      "useStoreContext must be used within a DataTableStoreProvider",
    );
  }
  return context;
}

/**
 * Adapter Interface Exports
 */

export type {
  StoreAdapter,
  CreateAdapterOptions,
  AdapterFactory,
  InternalStoreAdapter,
  AdapterType,
} from "./types";

/**
 * Adapter Interface for BYOS (Bring Your Own Store)
 *
 * This interface defines the contract that all store adapters must implement.
 * It is designed to be compatible with React 18's useSyncExternalStore.
 */

import type { SchemaDefinition, StoreSnapshot } from "../schema/types";

/**
 * Store adapter interface that all adapters must implement
 */
export interface StoreAdapter<T extends Record<string, unknown>> {
  /**
   * Subscribe to state changes.
   * Compatible with useSyncExternalStore's subscribe parameter.
   *
   * @param listener - Callback to invoke when state changes
   * @returns Unsubscribe function
   */
  subscribe(listener: () => void): () => void;

  /**
   * Get the current state snapshot.
   * Compatible with useSyncExternalStore's getSnapshot parameter.
   *
   * @returns Current state snapshot with version
   */
  getSnapshot(): StoreSnapshot<T>;

  /**
   * Get the server-side state snapshot (for SSR).
   * Only implemented by URL-based adapters.
   *
   * @returns Server state snapshot
   */
  getServerSnapshot?(): StoreSnapshot<T>;

  /**
   * Update state with partial values.
   * Must use immutable updates (new references for changed values).
   *
   * @param partial - Partial state to merge
   */
  setState(partial: Partial<T>): void;

  /**
   * Update a single field value.
   *
   * @param key - Field key
   * @param value - New value
   */
  setField<K extends keyof T>(key: K, value: T[K]): void;

  /**
   * Reset state to defaults.
   *
   * @param fields - Optional array of fields to reset. If omitted, resets all.
   */
  reset(fields?: (keyof T)[]): void;

  /**
   * Pause state updates (for live mode).
   * While paused, setState calls are queued.
   */
  pause(): void;

  /**
   * Resume state updates.
   * Applies any queued state changes.
   */
  resume(): void;

  /**
   * Check if updates are paused.
   */
  isPaused(): boolean;

  /**
   * Cleanup resources when adapter is destroyed.
   */
  destroy(): void;

  /**
   * Get the unique table ID for this adapter.
   */
  getTableId(): string;

  /**
   * Get the schema definition used by this adapter.
   */
  getSchema(): SchemaDefinition;

  /**
   * Get the default values from the schema.
   */
  getDefaults(): T;
}

/**
 * Options for creating an adapter
 */
export interface CreateAdapterOptions<T extends Record<string, unknown>> {
  /**
   * Unique ID for this table (required for multi-table support)
   */
  id: string;

  /**
   * Initial state to override defaults
   */
  initialState?: Partial<T>;
}

/**
 * Factory function type for creating adapters
 */
export type AdapterFactory<T extends Record<string, unknown>> = (
  schema: SchemaDefinition,
  options: CreateAdapterOptions<T>,
) => StoreAdapter<T>;

/**
 * Available adapter types
 */
export type AdapterType = "nuqs" | "zustand";

/**
 * Internal adapter with additional methods for providers
 * @internal
 */
export interface InternalStoreAdapter<T extends Record<string, unknown>>
  extends StoreAdapter<T> {
  /**
   * Internal method to sync external state (used by nuqs adapter)
   * @internal
   */
  _syncState?(state: T): void;

  /**
   * Internal method to get the state setter (used by nuqs adapter)
   * @internal
   */
  _getStateSetter?(): ((partial: Partial<T>) => void) | null;

  /**
   * Internal method to set the state setter (used by nuqs adapter)
   * @internal
   */
  _setStateSetter?(setter: (partial: Partial<T>) => void): void;
}

import { getSchemaDefaults } from "./serialization";
import type { InferSchemaType, Schema, SchemaDefinition } from "./types";

/**
 * Schema System for BYOS (Bring Your Own Store)
 *
 * Provides a fluent API for defining filter schemas with type inference.
 *
 * @example
 * ```typescript
 * import { createSchema, field } from '@/lib/store/schema';
 *
 * const schema = createSchema({
 *   regions: field.array(field.string()).default([]).delimiter(','),
 *   latency: field.array(field.number()).delimiter('-'),
 *   host: field.string().default(''),
 *   live: field.boolean().default(false),
 * });
 *
 * type FilterState = typeof schema._type;
 * ```
 */

export { field } from "./field";
export type {
  FieldBuilder,
  FieldConfig,
  SchemaDefinition,
  InferSchemaType,
  Schema,
  StoreSnapshot,
  AdapterOptions,
} from "./types";
export {
  getSchemaDefaults,
  serializeState,
  parseState,
  validateState,
  mergeWithDefaults,
  isStateEqual,
  stateToSearchString,
} from "./serialization";

/**
 * Create a schema from field definitions
 *
 * @param definition - Object mapping field names to field builders
 * @returns Schema object with definition, defaults, and type inference
 *
 * @example
 * ```typescript
 * const schema = createSchema({
 *   level: field.array(field.stringLiteral(['error', 'warn', 'info'])).default([]),
 *   latency: field.array(field.number()).delimiter('-'),
 *   host: field.string(),
 * });
 * ```
 */
export function createSchema<T extends SchemaDefinition>(
  definition: T,
): Schema<T> {
  const defaults = getSchemaDefaults(definition);

  return {
    definition,
    defaults,
    // This is a type-only property for inference
    _type: defaults,
  };
}

/**
 * Schema Types for BYOS (Bring Your Own Store)
 *
 * These types define the structure for filter schemas with a fluent API.
 */

// Primitive field types
export type PrimitiveType =
  | "string"
  | "number"
  | "boolean"
  | "timestamp"
  | "stringLiteral";

// Field configuration stored internally
export interface FieldConfig<T> {
  type: PrimitiveType | "array" | "sort";
  defaultValue: T;
  delimiter: string;
  serialize: (value: T) => string;
  parse: (value: string) => T | null;
  // For stringLiteral type
  literals?: readonly string[];
  // For array type
  itemConfig?: FieldConfig<unknown>;
}

// Field builder interface (fluent API)
export interface FieldBuilder<T> {
  /**
   * Set the default value for this field
   */
  default(value: T): FieldBuilder<T>;

  /**
   * Set the delimiter for serialization (used for arrays)
   */
  delimiter(separator: string): FieldBuilder<T>;

  /**
   * Custom serialization function
   */
  serialize(fn: (value: T) => string): FieldBuilder<T>;

  /**
   * Custom parse function
   */
  parse(fn: (value: string) => T | null): FieldBuilder<T>;

  /**
   * Internal config - do not use directly
   * @internal
   */
  readonly _config: FieldConfig<T>;
}

// Schema definition as a record of field builders

export type SchemaDefinition = Record<string, FieldBuilder<any>>;

// Infer the TypeScript type from a schema definition
export type InferSchemaType<T extends SchemaDefinition> = {
  [K in keyof T]: T[K] extends FieldBuilder<infer U> ? U : never;
};

// Schema object returned by createSchema
export interface Schema<T extends SchemaDefinition> {
  /**
   * The raw schema definition
   */
  readonly definition: T;

  /**
   * Get default values for all fields
   */
  readonly defaults: InferSchemaType<T>;

  /**
   * Inferred TypeScript type (for type inference only)
   */
  readonly _type: InferSchemaType<T>;
}

// Store snapshot with version for change detection
export interface StoreSnapshot<T> {
  state: T;
  version: number;
}

// Adapter options passed during creation
export interface AdapterOptions {
  /**
   * Unique ID for this table (required for multi-table support)
   */
  id: string;

  /**
   * Initial state to override defaults
   */
  initialState?: Record<string, unknown>;
}

/**
 * Field Builders for Schema Definition
 *
 * Provides a fluent API for defining filter field types with serialization.
 */

import {
  ARRAY_DELIMITER,
  SLIDER_DELIMITER,
  SORT_DELIMITER,
} from "@/lib/delimiters";
import type { FieldBuilder, FieldConfig } from "./types";

// Helper to create a field builder from config
function createFieldBuilder<T>(config: FieldConfig<T>): FieldBuilder<T> {
  const builder: FieldBuilder<T> = {
    default(value: T) {
      return createFieldBuilder({ ...config, defaultValue: value });
    },

    delimiter(separator: string) {
      // Update serialize/parse functions when delimiter changes for arrays
      if (config.type === "array" && config.itemConfig) {
        const itemConfig = config.itemConfig as FieldConfig<unknown>;
        return createFieldBuilder({
          ...config,
          delimiter: separator,
          serialize: (value: T) => {
            if (!Array.isArray(value)) return "";
            return value
              .map((item) => itemConfig.serialize(item))
              .join(separator);
          },
          parse: (str: string) => {
            if (!str) return config.defaultValue;
            const items = str.split(separator);
            const parsed = items
              .map((item) => itemConfig.parse(item))
              .filter(
                (item): item is NonNullable<typeof item> => item !== null,
              );
            return parsed as T;
          },
        });
      }
      return createFieldBuilder({ ...config, delimiter: separator });
    },

    serialize(fn: (value: T) => string) {
      return createFieldBuilder({ ...config, serialize: fn });
    },

    parse(fn: (value: string) => T | null) {
      return createFieldBuilder({ ...config, parse: fn });
    },

    get _config() {
      return config;
    },
  };

  return builder;
}

// String field
function string(): FieldBuilder<string | null> {
  return createFieldBuilder<string | null>({
    type: "string",
    defaultValue: null,
    delimiter: "",
    serialize: (value) => (value === null ? "" : String(value)),
    parse: (str) => (str === "" ? null : str),
  });
}

// Number field (integer)
function number(): FieldBuilder<number | null> {
  return createFieldBuilder<number | null>({
    type: "number",
    defaultValue: null,
    delimiter: "",
    serialize: (value) => (value === null ? "" : String(value)),
    parse: (str) => {
      if (str === "") return null;
      const num = parseInt(str, 10);
      return isNaN(num) ? null : num;
    },
  });
}

// Boolean field
function boolean(): FieldBuilder<boolean | null> {
  return createFieldBuilder<boolean | null>({
    type: "boolean",
    defaultValue: null,
    delimiter: "",
    serialize: (value) => (value === null ? "" : String(value)),
    parse: (str) => {
      if (str === "") return null;
      if (str === "true") return true;
      if (str === "false") return false;
      return null;
    },
  });
}

// Timestamp field (Date)
function timestamp(): FieldBuilder<Date | null> {
  return createFieldBuilder<Date | null>({
    type: "timestamp",
    defaultValue: null,
    delimiter: "",
    serialize: (value) => (value === null ? "" : String(value.getTime())),
    parse: (str) => {
      if (str === "") return null;
      const time = parseInt(str, 10);
      if (isNaN(time)) return null;
      const date = new Date(time);
      return isNaN(date.getTime()) ? null : date;
    },
  });
}

// String literal field (enum-like)
function stringLiteral<T extends readonly string[]>(
  literals: T,
): FieldBuilder<T[number] | null> {
  return createFieldBuilder<T[number] | null>({
    type: "stringLiteral",
    defaultValue: null,
    delimiter: "",
    literals,
    serialize: (value) => (value === null ? "" : String(value)),
    parse: (str) => {
      if (str === "") return null;
      return literals.includes(str as T[number]) ? (str as T[number]) : null;
    },
  });
}

// Array field
function array<T>(itemBuilder: FieldBuilder<T>): FieldBuilder<T[]> {
  const itemConfig = itemBuilder._config;
  const defaultDelimiter =
    itemConfig.type === "number" ? SLIDER_DELIMITER : ARRAY_DELIMITER;

  return createFieldBuilder<T[]>({
    type: "array",
    defaultValue: [],
    delimiter: defaultDelimiter,
    itemConfig: itemConfig as FieldConfig<unknown>,
    serialize: (value) => {
      if (!Array.isArray(value) || value.length === 0) return "";
      return value
        .map((item) => itemConfig.serialize(item))
        .join(defaultDelimiter);
    },
    parse: (str) => {
      if (!str) return [];
      const items = str.split(defaultDelimiter);
      const parsed = items
        .map((item) => itemConfig.parse(item))
        .filter((item): item is T => item !== null);
      return parsed;
    },
  });
}

// Sort field { id: string, desc: boolean }
function sort(): FieldBuilder<{ id: string; desc: boolean } | null> {
  return createFieldBuilder<{ id: string; desc: boolean } | null>({
    type: "sort",
    defaultValue: null,
    delimiter: SORT_DELIMITER,
    serialize: (value) => {
      if (value === null) return "";
      return `${value.id}${SORT_DELIMITER}${value.desc ? "desc" : "asc"}`;
    },
    parse: (str) => {
      if (!str) return null;
      const [id, desc] = str.split(SORT_DELIMITER);
      if (!id) return null;
      return { id, desc: desc === "desc" };
    },
  });
}

// Export field builders
export const field = {
  string,
  number,
  boolean,
  timestamp,
  stringLiteral,
  array,
  sort,
};

/**
 * Serialization Utilities for Schema
 *
 * Functions for serializing state to strings and parsing strings back to state.
 */

import type { FieldBuilder, InferSchemaType, SchemaDefinition } from "./types";

/**
 * Get default values from a schema definition
 */
export function getSchemaDefaults<T extends SchemaDefinition>(
  schema: T,
): InferSchemaType<T> {
  const defaults: Record<string, unknown> = {};

  for (const [key, fieldBuilder] of Object.entries(schema)) {
    defaults[key] = fieldBuilder._config.defaultValue;
  }

  return defaults as InferSchemaType<T>;
}

/**
 * Serialize state to a string map (for URL params or storage)
 */
export function serializeState<T extends SchemaDefinition>(
  schema: T,
  state: Partial<InferSchemaType<T>>,
): Record<string, string> {
  const result: Record<string, string> = {};

  for (const [key, value] of Object.entries(state)) {
    const fieldBuilder = schema[key] as FieldBuilder<unknown> | undefined;
    if (!fieldBuilder) continue;

    const serialized = fieldBuilder._config.serialize(value);
    if (serialized !== "") {
      result[key] = serialized;
    }
  }

  return result;
}

/**
 * Parse a string map back to state
 */
export function parseState<T extends SchemaDefinition>(
  schema: T,
  stringMap: Record<string, string | string[] | undefined>,
): Partial<InferSchemaType<T>> {
  const result: Record<string, unknown> = {};

  for (const [key, fieldBuilder] of Object.entries(schema)) {
    const rawValue = stringMap[key];
    if (rawValue === undefined) continue;

    // Handle array values from URL (Next.js can pass arrays)
    const strValue = Array.isArray(rawValue) ? rawValue.join(",") : rawValue;

    const parsed = (fieldBuilder as FieldBuilder<unknown>)._config.parse(
      strValue,
    );
    if (parsed !== null) {
      result[key] = parsed;
    }
  }

  return result as Partial<InferSchemaType<T>>;
}

/**
 * Validate and coerce state, returning defaults for invalid values
 */
export function validateState<T extends SchemaDefinition>(
  schema: T,
  state: unknown,
): InferSchemaType<T> {
  const defaults = getSchemaDefaults(schema);

  if (!state || typeof state !== "object") {
    return defaults;
  }

  const result: Record<string, unknown> = { ...defaults };

  for (const [key, fieldBuilder] of Object.entries(schema)) {
    const value = (state as Record<string, unknown>)[key];
    if (value === undefined) continue;

    // Serialize and re-parse to validate
    const config = (fieldBuilder as FieldBuilder<unknown>)._config;
    const serialized = config.serialize(value);
    const parsed = config.parse(serialized);

    if (parsed !== null) {
      result[key] = parsed;
    }
    // If invalid, default is already in result
  }

  return result as InferSchemaType<T>;
}

/**
 * Merge partial state with defaults
 */
export function mergeWithDefaults<T extends SchemaDefinition>(
  schema: T,
  partial: Partial<InferSchemaType<T>>,
): InferSchemaType<T> {
  const defaults = getSchemaDefaults(schema);
  return { ...defaults, ...partial };
}

/**
 * Check if two states are equal (shallow comparison for primitives, deep for arrays)
 */
export function isStateEqual<T extends Record<string, unknown>>(
  a: T,
  b: T,
): boolean {
  const keysA = Object.keys(a);
  const keysB = Object.keys(b);

  if (keysA.length !== keysB.length) return false;

  for (const key of keysA) {
    const valA = a[key];
    const valB = b[key];

    if (valA === valB) continue;

    // Handle arrays
    if (Array.isArray(valA) && Array.isArray(valB)) {
      if (valA.length !== valB.length) return false;
      for (let i = 0; i < valA.length; i++) {
        const itemA = valA[i];
        const itemB = valB[i];
        if (itemA instanceof Date && itemB instanceof Date) {
          if (itemA.getTime() !== itemB.getTime()) return false;
        } else if (itemA !== itemB) {
          return false;
        }
      }
      continue;
    }

    // Handle dates
    if (valA instanceof Date && valB instanceof Date) {
      if (valA.getTime() !== valB.getTime()) return false;
      continue;
    }

    // Handle objects (sort field)
    if (
      valA !== null &&
      valB !== null &&
      typeof valA === "object" &&
      typeof valB === "object"
    ) {
      const objA = valA as Record<string, unknown>;
      const objB = valB as Record<string, unknown>;
      if (!isStateEqual(objA, objB)) return false;
      continue;
    }

    return false;
  }

  return true;
}

/**
 * Create a URL search string from state
 */
export function stateToSearchString<T extends SchemaDefinition>(
  schema: T,
  state: Partial<InferSchemaType<T>>,
): string {
  const serialized = serializeState(schema, state);
  const params = new URLSearchParams();

  for (const [key, value] of Object.entries(serialized)) {
    if (value) {
      params.set(key, value);
    }
  }

  const str = params.toString();
  return str ? `?${str}` : "";
}

/**
 * Text Parser Exports
 */

export { createTextParser } from "./text-parser";
export type { TextParser, TextParserOptions } from "./types";

/**
 * Text Parser Types
 */

import type { InferSchemaType, SchemaDefinition } from "../schema/types";

/**
 * Options for creating a text parser
 */
export interface TextParserOptions {
  /**
   * Field aliases for shorthand (e.g., { l: 'level', r: 'regions' })
   */
  aliases?: Record<string, string>;

  /**
   * Delimiter between field:value pairs (default: ' ')
   */
  fieldDelimiter?: string;

  /**
   * Delimiter between field and value (default: ':')
   */
  keyValueDelimiter?: string;
}

/**
 * Text parser interface
 */
export interface TextParser<T extends SchemaDefinition> {
  /**
   * Parse a text input string into filter state
   *
   * @example
   * ```typescript
   * parser.parse('regions:ams,gru latency:0-1000');
   * // => { regions: ['ams', 'gru'], latency: [0, 1000] }
   * ```
   */
  parse(input: string): Partial<InferSchemaType<T>>;

  /**
   * Serialize filter state to text format
   *
   * @example
   * ```typescript
   * parser.serialize({ regions: ['ams', 'gru'], latency: [0, 1000] });
   * // => 'regions:ams,gru latency:0-1000'
   * ```
   */
  serialize(state: Partial<InferSchemaType<T>>): string;

  /**
   * Get the current word at caret position
   */
  getWordAtCaret(
    input: string,
    caretPosition: number,
  ): {
    word: string;
    start: number;
    end: number;
    field: string | null;
    value: string | null;
  };

  /**
   * Replace the current word at caret position
   */
  replaceWordAtCaret(
    input: string,
    caretPosition: number,
    replacement: string,
  ): {
    newInput: string;
    newCaretPosition: number;
  };

  /**
   * Get suggestions for autocomplete
   */
  getSuggestions(
    input: string,
    caretPosition: number,
    fieldOptions: Record<string, string[]>,
  ): {
    type: "field" | "value";
    field?: string;
    suggestions: string[];
  };
}

/**
 * Text Parser Implementation
 *
 * Standalone module for parsing filter command text input.
 */

import type {
  FieldBuilder,
  InferSchemaType,
  SchemaDefinition,
} from "../schema/types";
import type { TextParser, TextParserOptions } from "./types";

/**
 * Create a text parser for filter command input
 *
 * @example
 * ```typescript
 * import { createTextParser } from '@/lib/store/parser';
 *
 * const parser = createTextParser(schema.definition, {
 *   aliases: { l: 'level', r: 'regions' },
 * });
 *
 * // Parse text to state
 * const state = parser.parse('level:error,warn regions:ams');
 *
 * // Serialize state to text
 * const text = parser.serialize({ level: ['error', 'warn'], regions: ['ams'] });
 * ```
 */
export function createTextParser<T extends SchemaDefinition>(
  schema: T,
  options: TextParserOptions = {},
): TextParser<T> {
  const {
    aliases = {},
    fieldDelimiter = " ",
    keyValueDelimiter = ":",
  } = options;

  // Build reverse alias map
  const reverseAliases: Record<string, string> = {};
  for (const [alias, field] of Object.entries(aliases)) {
    reverseAliases[field] = alias;
  }

  // Resolve alias to field name
  const resolveAlias = (key: string): string => {
    return aliases[key] || key;
  };

  return {
    parse(input: string): Partial<InferSchemaType<T>> {
      const result: Record<string, unknown> = {};

      if (!input.trim()) {
        return result as Partial<InferSchemaType<T>>;
      }

      // Split by field delimiter, but handle quoted values
      const parts = input
        .trim()
        .split(new RegExp(`\\s*${escapeRegex(fieldDelimiter)}\\s*`));

      for (const part of parts) {
        if (!part) continue;

        const colonIndex = part.indexOf(keyValueDelimiter);
        if (colonIndex === -1) continue;

        const rawKey = part.slice(0, colonIndex).trim();
        const rawValue = part.slice(colonIndex + 1).trim();

        if (!rawKey || !rawValue) continue;

        const fieldKey = resolveAlias(rawKey);
        const fieldBuilder = schema[fieldKey] as
          | FieldBuilder<unknown>
          | undefined;

        if (!fieldBuilder) continue;

        try {
          const parsed = fieldBuilder._config.parse(rawValue);
          if (parsed !== null) {
            result[fieldKey] = parsed;
          }
        } catch {
          // Skip invalid values
        }
      }

      return result as Partial<InferSchemaType<T>>;
    },

    serialize(state: Partial<InferSchemaType<T>>): string {
      const parts: string[] = [];

      for (const [key, value] of Object.entries(state)) {
        if (value === null || value === undefined) continue;
        if (Array.isArray(value) && value.length === 0) continue;

        const fieldBuilder = schema[key] as FieldBuilder<unknown> | undefined;
        if (!fieldBuilder) continue;

        try {
          const serialized = fieldBuilder._config.serialize(value);
          if (serialized) {
            parts.push(`${key}${keyValueDelimiter}${serialized}`);
          }
        } catch {
          // Skip invalid values
        }
      }

      return parts.join(fieldDelimiter);
    },

    getWordAtCaret(input: string, caretPosition: number) {
      // Find word boundaries
      let start = caretPosition;
      let end = caretPosition;

      // Move start backwards to find word start
      while (start > 0 && input[start - 1] !== fieldDelimiter) {
        start--;
      }

      // Move end forwards to find word end
      while (end < input.length && input[end] !== fieldDelimiter) {
        end++;
      }

      const word = input.slice(start, end);
      const colonIndex = word.indexOf(keyValueDelimiter);

      let field: string | null = null;
      let value: string | null = null;

      if (colonIndex !== -1) {
        field = resolveAlias(word.slice(0, colonIndex));
        value = word.slice(colonIndex + 1);
      } else {
        // Could be a partial field name
        field = null;
        value = null;
      }

      return { word, start, end, field, value };
    },

    replaceWordAtCaret(
      input: string,
      caretPosition: number,
      replacement: string,
    ) {
      const { start, end } = this.getWordAtCaret(input, caretPosition);

      const before = input.slice(0, start);
      const after = input.slice(end);

      const newInput = before + replacement + after;
      const newCaretPosition = start + replacement.length;

      return { newInput, newCaretPosition };
    },

    getSuggestions(
      input: string,
      caretPosition: number,
      fieldOptions: Record<string, string[]>,
    ) {
      const { word, field, value } = this.getWordAtCaret(input, caretPosition);

      // If we have a field and are typing a value
      if (field && value !== null) {
        const options = fieldOptions[field] || [];
        const filtered = options.filter((opt) =>
          opt.toLowerCase().includes(value.toLowerCase()),
        );

        return {
          type: "value" as const,
          field,
          suggestions: filtered,
        };
      }

      // Otherwise, suggest field names
      const schemaKeys = Object.keys(schema);
      const aliasKeys = Object.keys(aliases);
      const allFields = [...schemaKeys, ...aliasKeys];

      const filtered = word
        ? allFields.filter((f) =>
            f.toLowerCase().startsWith(word.toLowerCase()),
          )
        : allFields;

      return {
        type: "field" as const,
        suggestions: filtered,
      };
    },
  };
}

/**
 * Escape special regex characters
 */
function escapeRegex(str: string): string {
  return str.replace(/[.*+?^${}()|[\]\\]/g, "\\$&");
}

/**
 * DataTableStoreProvider - Main provider for BYOS
 *
 * Wraps components with store adapter context.
 */

"use client";

import React, { useEffect, useMemo } from "react";
import type { StoreAdapter } from "../adapter/types";
import { StoreContext, type StoreContextValue } from "../context";

export interface DataTableStoreProviderProps<
  T extends Record<string, unknown>,
> {
  /**
   * The store adapter to use
   */
  adapter: StoreAdapter<T>;

  /**
   * Child components
   */
  children: React.ReactNode;
}

/**
 * Provider component for data table store
 *
 * @example
 * ```typescript
 * const adapter = useNuqsAdapter(schema.definition, { id: 'my-table' });
 *
 * return (
 *   <DataTableStoreProvider adapter={adapter}>
 *     <DataTable />
 *   </DataTableStoreProvider>
 * );
 * ```
 */
export function DataTableStoreProvider<T extends Record<string, unknown>>({
  adapter,
  children,
}: DataTableStoreProviderProps<T>) {
  const value = useMemo<StoreContextValue<T>>(
    () => ({
      adapter,
      schema: adapter.getSchema(),
      tableId: adapter.getTableId(),
    }),
    [adapter],
  );

  // Cleanup on unmount
  useEffect(() => {
    return () => {
      adapter.destroy();
    };
  }, [adapter]);

  return (
    <StoreContext.Provider
      value={value as StoreContextValue<Record<string, unknown>>}
    >
      {children}
    </StoreContext.Provider>
  );
}

/**
 * BYOS Hooks Exports
 */

export { useFilterState } from "./useFilterState";
export { useFilterActions, type FilterActions } from "./useFilterActions";
export { useFilterField, type FilterFieldResult } from "./useFilterField";
export { useReactTableSync } from "./useReactTableSync";

/**
 * useFilterState Hook
 *
 * Read filter state from the store adapter.
 */

"use client";

import { useCallback, useSyncExternalStore } from "react";
import { useStoreContext } from "../context";

/**
 * Hook to read filter state from the adapter
 *
 * @example
 * ```typescript
 * // Read entire state
 * const state = useFilterState();
 *
 * // Read with selector (for performance)
 * const regions = useFilterState(s => s.regions);
 * ```
 */
export function useFilterState<T extends Record<string, unknown>, R = T>(
  selector?: (state: T) => R,
): R {
  const context = useStoreContext();

  if (!context) {
    throw new Error(
      "useFilterState must be used within a DataTableStoreProvider",
    );
  }

  const { adapter } = context;

  const subscribe = useCallback(
    (onStoreChange: () => void) => adapter.subscribe(onStoreChange),
    [adapter],
  );

  const getSnapshot = useCallback(() => {
    const snapshot = adapter.getSnapshot();
    const state = snapshot.state as T;
    return selector ? selector(state) : (state as unknown as R);
  }, [adapter, selector]);

  const getServerSnapshot = useCallback(() => {
    const snapshot = adapter.getServerSnapshot?.() ?? adapter.getSnapshot();
    const state = snapshot.state as T;
    return selector ? selector(state) : (state as unknown as R);
  }, [adapter, selector]);

  return useSyncExternalStore(subscribe, getSnapshot, getServerSnapshot);
}

/**
 * useFilterActions Hook
 *
 * Get actions to modify filter state.
 */

"use client";

import { useCallback, useMemo } from "react";
import { useStoreContext } from "../context";

/**
 * Actions returned by useFilterActions
 */
export interface FilterActions<T extends Record<string, unknown>> {
  /**
   * Set a single filter field value
   */
  setFilter: <K extends keyof T>(key: K, value: T[K]) => void;

  /**
   * Set multiple filter fields at once
   */
  setFilters: (partial: Partial<T>) => void;

  /**
   * Reset a single filter field to its default value
   */
  resetFilter: (key: keyof T) => void;

  /**
   * Reset all filters to default values
   */
  resetAllFilters: () => void;

  /**
   * Pause state updates (for live mode)
   */
  pause: () => void;

  /**
   * Resume state updates
   */
  resume: () => void;

  /**
   * Check if updates are paused
   */
  isPaused: () => boolean;
}

/**
 * Hook to get filter actions
 *
 * @example
 * ```typescript
 * const { setFilter, setFilters, resetAllFilters, pause, resume } = useFilterActions();
 *
 * // Set single field
 * setFilter('regions', ['ams', 'gru']);
 *
 * // Set multiple fields
 * setFilters({ regions: ['ams'], host: 'api.example.com' });
 *
 * // Reset all
 * resetAllFilters();
 *
 * // Pause/resume for live mode
 * pause();
 * resume();
 * ```
 */
export function useFilterActions<
  T extends Record<string, unknown>,
>(): FilterActions<T> {
  const context = useStoreContext();

  if (!context) {
    throw new Error(
      "useFilterActions must be used within a DataTableStoreProvider",
    );
  }

  const { adapter } = context;

  const setFilter = useCallback(
    <K extends keyof T>(key: K, value: T[K]) => {
      adapter.setField(key as string, value);
    },
    [adapter],
  );

  const setFilters = useCallback(
    (partial: Partial<T>) => {
      adapter.setState(partial as Partial<Record<string, unknown>>);
    },
    [adapter],
  );

  const resetFilter = useCallback(
    (key: keyof T) => {
      adapter.reset([key as string]);
    },
    [adapter],
  );

  const resetAllFilters = useCallback(() => {
    adapter.reset();
  }, [adapter]);

  const pause = useCallback(() => {
    adapter.pause();
  }, [adapter]);

  const resume = useCallback(() => {
    adapter.resume();
  }, [adapter]);

  const isPaused = useCallback(() => {
    return adapter.isPaused();
  }, [adapter]);

  return useMemo(
    () => ({
      setFilter,
      setFilters,
      resetFilter,
      resetAllFilters,
      pause,
      resume,
      isPaused,
    }),
    [
      setFilter,
      setFilters,
      resetFilter,
      resetAllFilters,
      pause,
      resume,
      isPaused,
    ],
  );
}

/**
 * useFilterField Hook
 *
 * Hook for working with a single filter field.
 */

"use client";

import { useCallback, useMemo, useSyncExternalStore } from "react";
import { useStoreContext } from "../context";

/**
 * Return type for useFilterField
 */
export interface FilterFieldResult<T> {
  /**
   * Current value of the field
   */
  value: T;

  /**
   * Set the field value
   */
  setValue: (value: T) => void;

  /**
   * Reset the field to its default value
   */
  reset: () => void;
}

/**
 * Hook to work with a single filter field
 *
 * @example
 * ```typescript
 * const { value, setValue, reset } = useFilterField<FilterState, 'regions'>('regions');
 *
 * // Read value
 * console.log(value); // ['ams', 'gru']
 *
 * // Update value
 * setValue(['ams', 'gru', 'fra']);
 *
 * // Reset to default
 * reset();
 * ```
 */
export function useFilterField<
  T extends Record<string, unknown>,
  K extends keyof T,
>(key: K): FilterFieldResult<T[K]> {
  const context = useStoreContext();

  if (!context) {
    throw new Error(
      "useFilterField must be used within a DataTableStoreProvider",
    );
  }

  const { adapter } = context;

  const subscribe = useCallback(
    (onStoreChange: () => void) => adapter.subscribe(onStoreChange),
    [adapter],
  );

  const getSnapshot = useCallback(() => {
    const snapshot = adapter.getSnapshot();
    return (snapshot.state as T)[key];
  }, [adapter, key]);

  const getServerSnapshot = useCallback(() => {
    const snapshot = adapter.getServerSnapshot?.() ?? adapter.getSnapshot();
    return (snapshot.state as T)[key];
  }, [adapter, key]);

  const value = useSyncExternalStore(subscribe, getSnapshot, getServerSnapshot);

  const setValue = useCallback(
    (newValue: T[K]) => {
      adapter.setField(key as string, newValue);
    },
    [adapter, key],
  );

  const reset = useCallback(() => {
    adapter.reset([key as string]);
  }, [adapter, key]);

  return useMemo(() => ({ value, setValue, reset }), [value, setValue, reset]);
}

/**
 * useReactTableSync Hook
 *
 * Syncs BYOS filter state with React Table's columnFilters.
 * This hook provides bidirectional synchronization between the adapter state
 * and React Table's internal state.
 */

"use client";

import type { DataTableFilterField } from "@/components/data-table/types";
import type { ColumnFiltersState, Table } from "@tanstack/react-table";
import { useCallback, useEffect, useRef } from "react";
import { useFilterActions } from "./useFilterActions";
import { useFilterState } from "./useFilterState";

interface UseReactTableSyncOptions<TData> {
  /**
   * React Table instance
   */
  table: Table<TData>;

  /**
   * Filter field definitions (to know which fields to sync)
   */
  filterFields: DataTableFilterField<TData>[];

  /**
   * Callback when column filters change (from table)
   */
  onColumnFiltersChange?: (filters: ColumnFiltersState) => void;
}

/**
 * Hook to synchronize BYOS adapter state with React Table
 *
 * @example
 * ```typescript
 * const table = useReactTable({ ... });
 *
 * useReactTableSync({
 *   table,
 *   filterFields,
 * });
 * ```
 */
export function useReactTableSync<TData>({
  table,
  filterFields,
  onColumnFiltersChange,
}: UseReactTableSyncOptions<TData>) {
  const filterState = useFilterState<Record<string, unknown>>();
  const { setFilters } = useFilterActions<Record<string, unknown>>();

  // Track if we're currently syncing to avoid loops
  const isSyncingRef = useRef(false);

  // Sync BYOS state → React Table
  useEffect(() => {
    if (isSyncingRef.current) return;

    isSyncingRef.current = true;

    // Convert filter state to column filters format
    for (const field of filterFields) {
      const fieldKey = field.value as string;
      const value = filterState[fieldKey];
      const column = table.getColumn(fieldKey);

      if (column) {
        // Only update if value is different
        const currentValue = column.getFilterValue();
        if (!isEqual(currentValue, value)) {
          column.setFilterValue(value ?? undefined);
        }
      }
    }

    isSyncingRef.current = false;
  }, [filterState, filterFields, table]);

  // Sync React Table → BYOS state (via callback)
  const syncFromTable = useCallback(() => {
    if (isSyncingRef.current) return;

    isSyncingRef.current = true;

    const columnFilters = table.getState().columnFilters;
    const updates: Record<string, unknown> = {};

    for (const field of filterFields) {
      const fieldKey = field.value as string;
      const filter = columnFilters.find((f) => f.id === fieldKey);
      updates[fieldKey] = filter?.value ?? null;
    }

    setFilters(updates);
    onColumnFiltersChange?.(columnFilters);

    isSyncingRef.current = false;
  }, [table, filterFields, setFilters, onColumnFiltersChange]);

  return {
    syncFromTable,
  };
}

/**
 * Simple equality check for filter values
 */
function isEqual(a: unknown, b: unknown): boolean {
  if (a === b) return true;
  if (a === null || b === null) return a === b;
  if (a === undefined || b === undefined) return a === b;

  if (Array.isArray(a) && Array.isArray(b)) {
    if (a.length !== b.length) return false;
    return a.every((val, i) => isEqual(val, b[i]));
  }

  if (a instanceof Date && b instanceof Date) {
    return a.getTime() === b.getTime();
  }

  if (typeof a === "object" && typeof b === "object") {
    const keysA = Object.keys(a as object);
    const keysB = Object.keys(b as object);
    if (keysA.length !== keysB.length) return false;
    return keysA.every((key) =>
      isEqual(
        (a as Record<string, unknown>)[key],
        (b as Record<string, unknown>)[key],
      ),
    );
  }

  return false;
}

/**
 * In-Memory Adapter for BYOS
 *
 * A lightweight adapter that stores filter state in refs with a subscriber
 * pattern, compatible with React's useSyncExternalStore. No URL sync or
 * external store needed — ideal for the builder where state is ephemeral.
 */

"use client";

import { useCallback, useMemo, useRef } from "react";
import type { InternalStoreAdapter } from "../../adapter/types";
import { getSchemaDefaults } from "../../schema/serialization";
import type { SchemaDefinition, StoreSnapshot } from "../../schema/types";

export function useMemoryAdapter<T extends Record<string, unknown>>(
  schema: SchemaDefinition,
  options?: { id?: string },
): InternalStoreAdapter<T> {
  const defaults = useMemo(() => getSchemaDefaults(schema) as T, [schema]);

  const stateRef = useRef<T>({ ...defaults });
  const versionRef = useRef(0);
  const listenersRef = useRef(new Set<() => void>());
  const pausedRef = useRef(false);
  const pendingRef = useRef<Partial<T> | null>(null);

  const notify = useCallback(() => {
    for (const listener of listenersRef.current) {
      listener();
    }
  }, []);

  const adapter = useMemo<InternalStoreAdapter<T>>(() => {
    return {
      subscribe(listener: () => void) {
        listenersRef.current.add(listener);
        return () => {
          listenersRef.current.delete(listener);
        };
      },

      getSnapshot(): StoreSnapshot<T> {
        return {
          state: stateRef.current,
          version: versionRef.current,
        };
      },

      getServerSnapshot(): StoreSnapshot<T> {
        return {
          state: { ...defaults } as T,
          version: 0,
        };
      },

      setState(partial: Partial<T>) {
        if (pausedRef.current) {
          pendingRef.current = {
            ...(pendingRef.current ?? {}),
            ...partial,
          } as Partial<T>;
          return;
        }

        stateRef.current = { ...stateRef.current, ...partial };
        versionRef.current++;
        notify();
      },

      setField<K extends keyof T>(key: K, value: T[K]) {
        this.setState({ [key]: value } as unknown as Partial<T>);
      },

      reset(fields?: (keyof T)[]) {
        if (fields) {
          const resetPartial: Partial<T> = {};
          for (const field of fields) {
            resetPartial[field] = defaults[field];
          }
          this.setState(resetPartial);
        } else {
          stateRef.current = { ...defaults };
          versionRef.current++;
          notify();
        }
      },

      pause() {
        pausedRef.current = true;
      },

      resume() {
        pausedRef.current = false;
        if (pendingRef.current) {
          const pending = pendingRef.current;
          pendingRef.current = null;
          this.setState(pending);
        }
      },

      isPaused() {
        return pausedRef.current;
      },

      destroy() {
        listenersRef.current.clear();
      },

      getTableId() {
        return options?.id ?? "memory";
      },

      getSchema() {
        return schema;
      },

      getDefaults() {
        return defaults;
      },
    };
  }, [schema, defaults, notify]);

  return adapter;
}

